PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "schools" ("id" integer primary key autoincrement not null, "name" varchar not null, "location" varchar, "config_details" text, "created_at" datetime, "updated_at" datetime, "school_code" varchar);
CREATE TABLE IF NOT EXISTS "classes" ("id" integer primary key autoincrement not null, "name" varchar not null, "grade_level" varchar, "school_id" integer not null, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "room" varchar, "class_name" varchar, foreign key("school_id") references "schools"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "subjects" ("id" integer primary key autoincrement not null, "name" varchar not null, "school_id" integer not null, "created_at" datetime, "updated_at" datetime, "subject_code" varchar, "subject_name" varchar, "is_optional" tinyint(1) not null default '0', "full_score" numeric not null default '100', foreign key("school_id") references "schools"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "parent_child" ("parent_id" integer not null, "student_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("parent_id") references "users"("id") on delete cascade, foreign key("student_id") references "students"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "teacher_class" ("teacher_id" integer not null, "class_id" integer not null, "subject_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("teacher_id") references "users"("id") on delete cascade, foreign key("class_id") references "classes"("id") on delete cascade, foreign key("subject_id") references "subjects"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "homeworks" ("id" integer primary key autoincrement not null, "class_id" integer not null, "subject_id" integer not null, "title" varchar not null, "question" text, "due_date" date, "file_attachments" text, "created_at" datetime, "updated_at" datetime, "due_time" time, foreign key("class_id") references "classes"("id") on delete cascade, foreign key("subject_id") references "subjects"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "homeworkstatus" ("id" integer primary key autoincrement not null, "homework_id" integer not null, "student_id" integer not null, "status" varchar not null, "completion_date" date, "created_at" datetime, "updated_at" datetime, foreign key("homework_id") references "homeworks"("id") on delete cascade, foreign key("student_id") references "students"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "scores" ("id" integer primary key autoincrement not null, "student_id" integer not null, "subject_id" integer not null, "class_id" integer not null, "exam_score" numeric not null default '0', "total_score" numeric not null default '0', "month" integer, "quarter" integer, "period" varchar, "grade" varchar, "created_at" datetime, "updated_at" datetime, "assessment_type" varchar not null default 'monthly', "semester" integer, "academic_year" varchar, "rank_in_class" integer, foreign key("student_id") references "students"("id") on delete cascade, foreign key("subject_id") references "subjects"("id") on delete cascade, foreign key("class_id") references "classes"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "messages" ("id" integer primary key autoincrement not null, "sender_id" integer not null, "receiver_id" integer, "class_id" integer, "content" text not null, "date" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("sender_id") references "users"("id") on delete cascade, foreign key("receiver_id") references "users"("id") on delete set null, foreign key("class_id") references "classes"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "notification" ("id" integer primary key autoincrement not null, "user_id" integer not null, "title" varchar not null, "content" text not null, "date" datetime not null, "read_status" tinyint(1) not null default '0', foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "incidentreport" ("id" integer primary key autoincrement not null, "student_id" integer not null, "description" text not null, "date" date not null, "type" varchar, "acknowledged" tinyint(1) not null default '0', "reporter_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("student_id") references "students"("id") on delete cascade, foreign key("reporter_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "audit_logs" ("id" integer primary key autoincrement not null, "actor_id" integer, "school_id" integer, "actor_name" varchar not null, "actor_role" varchar not null, "method" varchar not null, "endpoint" varchar not null, "action" varchar not null, "resource_type" varchar, "resource_id" integer, "ip_address" varchar, "user_agent" text, "request_payload" text, "status_code" integer, "created_at" datetime, "updated_at" datetime, foreign key("actor_id") references "users"("id") on delete set null, foreign key("school_id") references "schools"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "roles" ("role_id" integer primary key autoincrement not null, "role_name" varchar not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "school_id" integer, "role" varchar not null default ('student'), "phone" varchar, "password_hash" varchar, "address" varchar, "bio" text, "image_url" text, "active" tinyint(1) not null default ('1'), "last_login" datetime, "deleted_at" datetime, "user_code" varchar, "first_name" varchar, "last_name" varchar, "khmer_name" varchar, "gender" varchar, "dob" date, "username" varchar, "role_id" integer, "is_active" tinyint(1) not null default ('1'), foreign key("school_id") references schools("id") on delete set null on update no action, foreign key("role_id") references "roles"("role_id") on delete set null);
CREATE TABLE IF NOT EXISTS "academic_years" ("academic_year_id" integer primary key autoincrement not null, "year_name" varchar not null, "start_date" date not null, "end_date" date not null, "is_current" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "terms" ("term_id" integer primary key autoincrement not null, "academic_year_id" integer not null, "term_name" varchar not null, "start_date" date not null, "end_date" date not null, "created_at" datetime, "updated_at" datetime, foreign key("academic_year_id") references "academic_years"("academic_year_id") on delete cascade);
CREATE TABLE IF NOT EXISTS "guardians" ("guardian_id" integer primary key autoincrement not null, "user_id" integer, "first_name" varchar not null, "last_name" varchar not null, "relationship_to_student" varchar not null, "phone" varchar, "email" varchar, "address" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "student_guardians" ("student_id" integer not null, "guardian_id" integer not null, "is_primary" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("student_id") references "students"("id") on delete cascade, foreign key("guardian_id") references "guardians"("guardian_id") on delete cascade, primary key ("student_id", "guardian_id"));
CREATE TABLE IF NOT EXISTS "teachers" ("teacher_id" integer primary key autoincrement not null, "user_id" integer, "employee_no" varchar not null, "first_name" varchar not null, "last_name" varchar not null, "phone" varchar, "email" varchar, "specialization" varchar, "hire_date" date not null, "status" varchar check ("status" in ('Active', 'On Leave', 'Inactive')) not null default 'Active', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "sections" ("section_id" integer primary key autoincrement not null, "class_id" integer not null, "academic_year_id" integer not null, "section_name" varchar not null, "class_teacher_id" integer, "room_no" varchar, "created_at" datetime, "updated_at" datetime, foreign key("class_id") references "classes"("id") on delete cascade, foreign key("academic_year_id") references "academic_years"("academic_year_id") on delete cascade, foreign key("class_teacher_id") references "teachers"("teacher_id") on delete set null);
CREATE TABLE IF NOT EXISTS "teacher_assignments" ("assignment_id" integer primary key autoincrement not null, "teacher_id" integer not null, "subject_id" integer not null, "section_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("subject_id") references "subjects"("id") on delete cascade, foreign key("teacher_id") references "teachers"("teacher_id") on delete cascade, foreign key("section_id") references "sections"("section_id") on delete cascade);
CREATE TABLE IF NOT EXISTS "enrollments" ("enrollment_id" integer primary key autoincrement not null, "student_id" integer not null, "academic_year_id" integer not null, "class_id" integer not null, "section_id" integer not null, "roll_no" varchar, "enrollment_date" date not null, "status" varchar check ("status" in ('Enrolled', 'Promoted', 'Completed', 'Dropped')) not null default 'Enrolled', "created_at" datetime, "updated_at" datetime, foreign key("class_id") references "classes"("id") on delete cascade, foreign key("student_id") references "students"("id") on delete cascade, foreign key("academic_year_id") references "academic_years"("academic_year_id") on delete cascade, foreign key("section_id") references "sections"("section_id") on delete cascade);
CREATE TABLE IF NOT EXISTS "exams" ("exam_id" integer primary key autoincrement not null, "term_id" integer not null, "exam_name" varchar not null, "start_date" date, "end_date" date, "created_at" datetime, "updated_at" datetime, foreign key("term_id") references "terms"("term_id") on delete cascade);
CREATE TABLE IF NOT EXISTS "exam_subjects" ("exam_subject_id" integer primary key autoincrement not null, "exam_id" integer not null, "subject_id" integer not null, "max_marks" numeric not null default '100', "pass_marks" numeric not null default '40', "created_at" datetime, "updated_at" datetime, foreign key("subject_id") references "subjects"("id") on delete cascade, foreign key("exam_id") references "exams"("exam_id") on delete cascade);
CREATE TABLE IF NOT EXISTS "marks" ("mark_id" integer primary key autoincrement not null, "exam_subject_id" integer not null, "enrollment_id" integer not null, "obtained_marks" numeric not null, "grade_letter" varchar, "remarks" varchar, "created_at" datetime, "updated_at" datetime, foreign key("exam_subject_id") references "exam_subjects"("exam_subject_id") on delete cascade, foreign key("enrollment_id") references "enrollments"("enrollment_id") on delete cascade);
CREATE TABLE IF NOT EXISTS "fee_types" ("fee_type_id" integer primary key autoincrement not null, "fee_name" varchar not null, "description" varchar, "default_amount" numeric not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "student_fees" ("student_fee_id" integer primary key autoincrement not null, "enrollment_id" integer not null, "fee_type_id" integer not null, "amount_due" numeric not null, "due_date" date not null, "status" varchar check ("status" in ('Unpaid', 'Partially Paid', 'Paid', 'Waived')) not null default 'Unpaid', "created_at" datetime, "updated_at" datetime, foreign key("enrollment_id") references "enrollments"("enrollment_id") on delete cascade, foreign key("fee_type_id") references "fee_types"("fee_type_id") on delete cascade);
CREATE TABLE IF NOT EXISTS "payments" ("payment_id" integer primary key autoincrement not null, "student_fee_id" integer not null, "amount_paid" numeric not null, "payment_date" date not null, "payment_method" varchar check ("payment_method" in ('Cash', 'Bank', 'Card', 'Mobile Money')) not null, "reference_no" varchar, "received_by" integer, "created_at" datetime, "updated_at" datetime, foreign key("received_by") references "users"("id") on delete set null, foreign key("student_fee_id") references "student_fees"("student_fee_id") on delete cascade);
CREATE TABLE IF NOT EXISTS "timetables" ("id" integer primary key autoincrement not null, "class_id" integer not null, "subject_id" integer not null, "teacher_id" integer not null, "day_of_week" varchar not null, "time_start" time not null, "time_end" time not null, "created_at" datetime, "updated_at" datetime, "section_id" integer, "room_no" varchar, foreign key("teacher_id") references users("id") on delete cascade on update no action, foreign key("subject_id") references subjects("id") on delete cascade on update no action, foreign key("class_id") references classes("id") on delete cascade on update no action, foreign key("section_id") references "sections"("section_id") on delete set null);
CREATE TABLE IF NOT EXISTS "students" ("id" integer primary key autoincrement not null, "user_id" integer not null, "grade" varchar, "class_id" integer, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "student_code" varchar, "parent_name" varchar, "admission_no" varchar, "first_name" varchar, "last_name" varchar, "gender" varchar, "date_of_birth" date, "phone" varchar, "email" varchar, "address" text, "admission_date" date, "status" varchar not null default ('Active'), foreign key("class_id") references classes("id") on delete cascade on update no action, foreign key("user_id") references users("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "media" ("id" integer primary key autoincrement not null, "school_id" integer, "uploaded_by_user_id" integer, "mediable_type" varchar not null, "mediable_id" integer not null, "category" varchar not null default 'general', "disk" varchar not null default 'public', "directory" varchar, "path" varchar not null, "url" text not null, "original_name" varchar not null, "mime_type" varchar, "extension" varchar, "size_bytes" integer, "is_primary" tinyint(1) not null default '0', "metadata" text, "created_at" datetime, "updated_at" datetime, foreign key("school_id") references "schools"("id") on delete set null, foreign key("uploaded_by_user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "announcements" ("id" integer primary key autoincrement not null, "title" varchar not null, "content" text not null, "date" date not null, "school_id" integer not null, "class_id" integer, "created_at" datetime, "updated_at" datetime, "message" text, "audience" varchar not null default ('All'), "posted_by" integer, "file_attachments" text, "target_role" varchar, "target_user_id" integer, foreign key("posted_by") references users("id") on delete set null on update no action, foreign key("school_id") references schools("id") on delete cascade on update no action, foreign key("class_id") references classes("id") on delete set null on update no action, foreign key("target_user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "leaverequest" ("id" integer primary key autoincrement not null, "student_id" integer not null, "subject_id" integer, "request_type" varchar not null, "start_date" date not null, "start_time" time, "reason" text, "status" varchar not null default ('pending'), "submitted_by" integer, "created_at" datetime, "updated_at" datetime, "end_date" date, "end_time" time, "return_date" date, "total_days" integer, "subject_ids" text, "approved_by" integer, "approved_at" datetime, foreign key("submitted_by") references users("id") on delete set null on update no action, foreign key("subject_id") references subjects("id") on delete set null on update no action, foreign key("student_id") references students("id") on delete cascade on update no action, foreign key("approved_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "leave_request_recipients" ("id" integer primary key autoincrement not null, "leave_request_id" integer not null, "user_id" integer not null, "recipient_role" varchar, "created_at" datetime, "updated_at" datetime, foreign key("leave_request_id") references "leaverequest"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "message_reads" ("id" integer primary key autoincrement not null, "message_id" integer not null, "user_id" integer not null, "seen_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("message_id") references "messages"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "attendance" ("id" integer primary key autoincrement not null, "student_id" integer not null, "class_id" integer not null, "date" date not null, "time_start" time not null, "time_end" time, "status" varchar not null, "created_at" datetime, "updated_at" datetime, "enrollment_id" integer, "attendance_date" date, "remarks" varchar, "subject_id" integer, foreign key("enrollment_id") references enrollments("enrollment_id") on delete set null on update no action, foreign key("student_id") references students("id") on delete cascade on update no action, foreign key("class_id") references classes("id") on delete cascade on update no action, foreign key("subject_id") references "subjects"("id") on delete set null);
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "classes_school_name_grade_unique" on "classes" ("school_id", "name", "grade_level");
CREATE INDEX "classes_school_id_index" on "classes" ("school_id");
CREATE UNIQUE INDEX "subjects_school_name_unique" on "subjects" ("school_id", "name");
CREATE INDEX "subjects_school_id_index" on "subjects" ("school_id");
CREATE UNIQUE INDEX "parent_child_parent_student_unique" on "parent_child" ("parent_id", "student_id");
CREATE UNIQUE INDEX "teacher_class_unique" on "teacher_class" ("teacher_id", "class_id", "subject_id");
CREATE INDEX "homeworks_class_id_index" on "homeworks" ("class_id");
CREATE INDEX "homeworks_subject_id_index" on "homeworks" ("subject_id");
CREATE INDEX "homeworks_due_date_index" on "homeworks" ("due_date");
CREATE UNIQUE INDEX "homeworkstatus_homework_student_unique" on "homeworkstatus" ("homework_id", "student_id");
CREATE INDEX "homeworkstatus_status_index" on "homeworkstatus" ("status");
CREATE INDEX "scores_student_id_index" on "scores" ("student_id");
CREATE INDEX "scores_class_id_index" on "scores" ("class_id");
CREATE INDEX "scores_subject_id_index" on "scores" ("subject_id");
CREATE INDEX "scores_student_month_quarter_period_index" on "scores" ("student_id", "month", "quarter", "period");
CREATE INDEX "messages_sender_id_index" on "messages" ("sender_id");
CREATE INDEX "messages_receiver_id_index" on "messages" ("receiver_id");
CREATE INDEX "messages_class_id_index" on "messages" ("class_id");
CREATE INDEX "messages_date_index" on "messages" ("date");
CREATE INDEX "notification_user_id_index" on "notification" ("user_id");
CREATE INDEX "notification_read_status_index" on "notification" ("read_status");
CREATE INDEX "notification_date_index" on "notification" ("date");
CREATE INDEX "incidentreport_student_id_index" on "incidentreport" ("student_id");
CREATE INDEX "incidentreport_type_index" on "incidentreport" ("type");
CREATE INDEX "incidentreport_acknowledged_index" on "incidentreport" ("acknowledged");
CREATE INDEX "incidentreport_date_index" on "incidentreport" ("date");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
CREATE INDEX "audit_logs_actor_id_created_at_index" on "audit_logs" ("actor_id", "created_at");
CREATE INDEX "audit_logs_school_id_created_at_index" on "audit_logs" ("school_id", "created_at");
CREATE INDEX "audit_logs_actor_role_created_at_index" on "audit_logs" ("actor_role", "created_at");
CREATE INDEX "audit_logs_resource_type_resource_id_index" on "audit_logs" ("resource_type", "resource_id");
CREATE INDEX "audit_logs_method_created_at_index" on "audit_logs" ("method", "created_at");
CREATE INDEX "scores_class_subject_assessment_window_index" on "scores" ("class_id", "subject_id", "assessment_type", "academic_year", "month", "semester");
CREATE INDEX "scores_student_assessment_year_index" on "scores" ("student_id", "assessment_type", "academic_year");
CREATE INDEX "scores_rank_in_class_index" on "scores" ("rank_in_class");
CREATE INDEX "classes_room_index" on "classes" ("room");
CREATE UNIQUE INDEX "roles_role_name_unique" on "roles" ("role_name");
CREATE INDEX "users_role_index" on "users" ("role");
CREATE UNIQUE INDEX "users_school_id_email_unique" on "users" ("school_id", "email");
CREATE INDEX "users_school_id_index" on "users" ("school_id");
CREATE UNIQUE INDEX "users_school_id_user_code_unique" on "users" ("school_id", "user_code");
CREATE INDEX "users_user_code_index" on "users" ("user_code");
CREATE UNIQUE INDEX "users_username_unique" on "users" ("username");
CREATE INDEX "users_role_id_index" on "users" ("role_id");
CREATE UNIQUE INDEX "academic_years_year_name_unique" on "academic_years" ("year_name");
CREATE UNIQUE INDEX "terms_year_term_name_unique" on "terms" ("academic_year_id", "term_name");
CREATE UNIQUE INDEX "teachers_employee_no_unique" on "teachers" ("employee_no");
CREATE UNIQUE INDEX "sections_class_year_name_unique" on "sections" ("class_id", "academic_year_id", "section_name");
CREATE UNIQUE INDEX "teacher_assignments_unique" on "teacher_assignments" ("teacher_id", "subject_id", "section_id");
CREATE UNIQUE INDEX "enrollments_student_year_unique" on "enrollments" ("student_id", "academic_year_id");
CREATE UNIQUE INDEX "enrollments_section_roll_no_unique" on "enrollments" ("section_id", "roll_no");
CREATE UNIQUE INDEX "exam_subjects_exam_subject_unique" on "exam_subjects" ("exam_id", "subject_id");
CREATE UNIQUE INDEX "marks_exam_subject_enrollment_unique" on "marks" ("exam_subject_id", "enrollment_id");
CREATE UNIQUE INDEX "fee_types_fee_name_unique" on "fee_types" ("fee_name");
CREATE UNIQUE INDEX "student_fees_unique" on "student_fees" ("enrollment_id", "fee_type_id", "due_date");
