CREATE INDEX "timetables_subject_id_index" on "timetables" ("subject_id");
CREATE INDEX "timetables_teacher_id_index" on "timetables" ("teacher_id");
CREATE INDEX "timetables_section_id_index" on "timetables" ("section_id");
