CREATE INDEX "homeworks_due_date_due_time_index" on "homeworks" ("due_date", "due_time");
CREATE INDEX "announcements_class_id_index" on "announcements" ("class_id");
CREATE INDEX "announcements_date_index" on "announcements" ("date");
CREATE INDEX "announcements_school_id_index" on "announcements" ("school_id");
